// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/alarm", wrapper.AlarmIndex)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/config/{realm}/{configContext}", wrapper.FetchContext)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/config/{realm}/{configContext}", wrapper.UpsertContext)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/group", wrapper.NewGroup)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/group/index", wrapper.SearchGroup)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/group/{groupId}", wrapper.DeleteGroup)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/group/{groupId}", wrapper.GetConfiguration)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/group/{group}/alarm", wrapper.DeleteGroupAlarm)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/group/{group}/alarm", wrapper.FetchGroupAlarms)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/group/{group}/alarm", wrapper.CreateGroupAlarm)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/group/{group}/member", wrapper.DeleteGroupMembers)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/group/{group}/member", wrapper.GroupMembers)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/group/{group}/member", wrapper.CreateGroupMember)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/group/{group}/message", wrapper.DeleteGroupMessage)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/group/{group}/message", wrapper.SearchMessage)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/group/{group}/message", wrapper.CreateGroupMessage)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/service", wrapper.NewService)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/service/index", wrapper.SearchService)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/service/{service}", wrapper.DeleteService)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/service/{service}", wrapper.ServiceById)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/service/{service}", wrapper.ServiceUpdate)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/service/{service}/alarm", wrapper.ServiceMessage)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/service/{service}/message", wrapper.ServiceActiveMessage)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/snippet", wrapper.UserSnippets)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/snippet", wrapper.NewSnippet)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/snippet/{snippet}", wrapper.DeleteSnippet)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/snippet/{snippet}", wrapper.GetSnippet)
	})

	return r
}

